class SecureModelRegistry:
    """
    Maintains an allowlist of approved model artifacts with their
    cryptographic checksums. This prevents model poisoning by ensuring
    only pre-approved, integrity-verified models can be loaded.
    """

    def __init__(self, registry_path: str):
        self._registry: Dict[str, Any] = {}
        self._load_registry(registry_path)

    def _load_registry(self, registry_path: str):
        """Load the model registry from a secure, read-only config file."""
        path = Path(registry_path)
        if not path.exists():
            raise FileNotFoundError(
                f"Model registry not found. A registry file with approved "
                f"model checksums is required for secure operation."
            )

        # Ensure registry file has restrictive permissions (owner read-only)
        file_stat = path.stat()
        file_mode = oct(file_stat.st_mode)[-3:]
        if file_mode not in ('400', '440', '444', '600', '640', '644'):
            logger.warning(
                "Model registry file has permissive permissions: %s. "
                "Recommend setting to 400 (owner read-only).", file_mode
            )

        with open(path, 'r') as f:
            self._registry = json.load(f)

        if "approved_models" not in self._registry:
            raise ValueError("Registry must contain 'approved_models' section")

        logger.info(
            "Loaded model registry with %d approved models",
            len(self._registry["approved_models"])
        )

    def get_approved_checksum(self, model_name: str, version: str) -> Optional[str]:
        """Get the approved SHA-256 checksum for a specific model version."""
        models = self._registry.get("approved_models", {})
        model_entry = models.get(model_name, {})
        return model_entry.get(version, {}).get("sha256")

    def is_model_approved(self, model_name: str, version: str) -> bool:
        """Check if a model name and version are in the approved allowlist."""
        models = self._registry.get("approved_models", {})
        if model_name not in models:
            return False
        return version in models[model_name]

    def get_approved_format(self, model_name: str, version: str) -> Optional[str]:
        """Get the approved serialization format for a model."""
        models = self._registry.get("approved_models", {})
        model_entry = models.get(model_name, {})
        return model_entry.get(version, {}).get("format")

    def get_latest_approved_version(self, model_name: str) -> Optional[str]:
        """Get the latest approved version for a model."""
        models = self._registry.get("approved_models", {})
        model_entry = models.get(model_name, {})
        if not model_entry:
            return None
        # Versions are stored with metadata; sort by approval timestamp
        versions = []
        for ver, meta in model_entry.items():
            if "approved_at" in meta:
                versions.append((ver, meta["approved_at"]))
        if not versions:
            return None
        versions.sort(key=lambda x: x[1], reverse=True)
        return versions[0][0]


class SecureModelLoader:
    """
    Securely loads ML models from cloud storage with:
    - Model allowlist validation (only approved models can be loaded)
    - Cryptographic integrity verification (SHA-256 checksums)
    - Safe deserialization (no pickle, only safe formats)
    - Least-privilege cloud access
    - Input validation and path traversal prevention
    """

    # Allowlist of safe model formats that don't use pickle
    SAFE_FORMATS = frozenset({
        'onnx',       # ONNX Runtime - safe binary format
        'savedmodel', # TensorFlow SavedModel - protobuf based
        'safetensors', # HuggingFace safetensors - safe by design
    })

    # Regex for valid model names and versions
    MODEL_NAME_PATTERN = re.compile(r'^[a-zA-Z0-9][a-zA-Z0-9_\-]{0,127}$')
    VERSION_PATTERN = re.compile(r'^v?\d+\.\d+\.\d+$')

    # Valid S3 bucket name pattern
    BUCKET_PATTERN = re.compile(r'^[a-z0-9][a-z0-9.\-]{1,61}[a-z0-9]$')

    def __init__(self):
        self._model = None
        self._model_metadata: Dict[str, Any] = {}
        self._temp_dir: Optional[str] = None

        # Load configuration from environment
        self._bucket_name = self._validate_bucket_name(
            os.environ.get('MODEL_BUCKET', '')
        )
        self._model_path_prefix = self._validate_path_prefix(
            os.environ.get('MODEL_PATH_PREFIX', '')
        )
        self._model_name = self._validate_model_name(
            os.environ.get('MODEL_NAME', '')
        )
        self._registry_path = os.environ.get(
            'MODEL_REGISTRY_PATH', '/etc/ml-service/model_registry.json'
        )

        # Initialize the model registry (allowlist of approved models)
        self._registry = SecureModelRegistry(self._registry_path)

        # Initialize S3 client with minimal permissions and TLS enforcement
        self._s3_client = self._create_secure_s3_client()

        # Create secure temporary directory for model downloads
        self._temp_dir = tempfile.mkdtemp(prefix='ml_model_')
        os.chmod(self._temp_dir, 0o700)

        logger.info(
            "SecureModelLoader initialized for model: %s", self._model_name
        )

    def _validate_bucket_name(self, bucket: str) -> str:
        """Validate S3 bucket name against allowlist pattern."""
        if not bucket:
            raise ValueError("MODEL_BUCKET environment variable is required")
        bucket = bucket.strip()
        if not self.BUCKET_PATTERN.match(bucket):
            raise ValueError(f"Invalid bucket name format")

        # Additional allowlist: only allow specific known buckets
        allowed_buckets_str = os.environ.get('ALLOWED_BUCKETS', '')
        if allowed_buckets_str:
            allowed_buckets = frozenset(
                b.strip() for b in allowed_buckets_str.split(',') if b.strip()
            )
            if bucket not in allowed_buckets:
                raise ValueError("Bucket not in allowed buckets list")

        return bucket

    def _validate_path_prefix(self, prefix: str) -> str:
        """Validate and sanitize the model path prefix."""
        if not prefix:
            raise ValueError("MODEL_PATH_PREFIX environment variable is required")

        prefix = prefix.strip().strip('/')

        # Prevent path traversal
        if '..' in prefix or prefix.startswith('/'):
            raise ValueError("Invalid path prefix: path traversal detected")

        # Only allow alphanumeric, hyphens, underscores, and forward slashes
        if not re.match(r'^[a-zA-Z0-9/_\-]+$', prefix):
            raise ValueError("Invalid characters in path prefix")

        return prefix

    def _validate_model_name(self, name: str) -> str:
        """Validate model name against allowlist pattern."""
        if not name:
            raise ValueError("MODEL_NAME environment variable is required")
        name = name.strip()
        if not self.MODEL_NAME_PATTERN.match(name):
            raise ValueError("Invalid model name format")
        return name

    def _validate_version(self, version: str) -> str:
        """Validate version string format."""
        version = version.strip()
        if not self.VERSION_PATTERN.match(version):
            raise ValueError(f"Invalid version format: must match pattern vX.Y.Z")
        return version

    def _create_secure_s3_client(self):
        """Create an S3 client with security best practices."""
        boto_config = BotoConfig(
            signature_version='s3v4',
            s3={'addressing_style': 'virtual'},
            retries={'max_attempts': 3, 'mode': 'standard'},
            connect_timeout=10,
            read_timeout=30,
        )

        # Use IAM role credentials (no hardcoded keys)
        # The service should run with a role that has minimal S3 read-only access
        client = boto3.client(
            's3',
            config=boto_config,
            # TLS is enforced by default in boto3
        )

        return client

    def _compute_sha256(self, file_path: str) -> str:
        """Compute SHA-256 checksum of a file."""
        sha256_hash = hashlib.sha256()
        with open(file_path, 'rb') as f:
            for chunk in iter(lambda: f.read(8192), b''):
                sha256_hash.update(chunk)
        return sha256_hash.hexdigest()

    def _verify_integrity(
        self, file_path: str, expected_checksum: str
    ) -> bool:
        """Verify file integrity using SHA-256 checksum comparison."""
        actual_checksum = self._compute_sha256(file_path)
        # Use constant-time comparison to prevent timing attacks
        return hmac.compare_digest(actual_checksum, expected_checksum)

    def _download_model_artifact(
        self, s3_key: str, local_path: str, max_size_bytes: int = 10 * 1024 * 1024 * 1024
    ) -> str:
        """Download model artifact from S3 with size limits."""
        # Check file size before downloading
        try:
            head_response = self._s3_client.head_object(
                Bucket=self._bucket_name,
                Key=s3_key
            )
        except ClientError as e:
            error_code = e.response['Error']['Code']
            if error_code == '404':
                raise ModelLoadError(f"Model artifact not found in storage")
            elif error_code == '403':
                raise ModelLoadError(f"Access denied to model artifact")
            raise ModelLoadError(f"Failed to check model artifact: {error_code}")

        content_length = head_response.get('ContentLength', 0)
        if content_length > max_size_bytes:
            raise ModelLoadError(
                f"Model artifact exceeds maximum allowed size "
                f"({content_length} > {max_size_bytes})"
            )

        if content_length == 0:
            raise ModelLoadError("Model artifact is empty")

        # Ensure local path is within our temp directory (prevent path traversal)
        local_path = os.path.realpath(local_path)
        temp_dir_real = os.path.realpath(self._temp_dir)
        if not local_path.startswith(temp_dir_real + os.sep):
            raise ModelLoadError("Invalid local path: outside temp directory")

        try:
            self._s3_client.download_file(
                self._bucket_name,
                s3_key,
                local_path
            )
        except ClientError as e:
            raise ModelLoadError(f"Failed to download model artifact")

        # Verify downloaded file size matches expected
        actual_size = os.path.getsize(local_path)
        if actual_size != content_length:
            os.unlink(local_path)
            raise ModelIntegrityError(
                "Downloaded file size mismatch - possible tampering"
            )

        return local_path

    def _load_onnx_model(self, model_path: str):
        """Load an ONNX model using ONNX Runtime."""
        try:
            import onnxruntime as ort

            # Use safe session options
            sess_options = ort.SessionOptions()
            sess_options.log_severity_level = 2  # Warning level

            session = ort.InferenceSession(
                model_path,
                sess_options=sess_options,
                providers=['CPUExecutionProvider']
            )
            return session
        except ImportError:
            raise ModelLoadError("onnxruntime is required for ONNX models")
        except Exception as e:
            raise ModelLoadError(f"Failed to load ONNX model: {type(e).__name__}")

    def _load_savedmodel(self, model_path: str):
        """Load a TensorFlow SavedModel."""
        try:
            import tensorflow as tf

            model = tf.saved_model.load(model_path)
            return model
        except ImportError:
            raise ModelLoadError("tensorflow is required for SavedModel format")
        except Exception as e:
            raise ModelLoadError(
                f"Failed to load SavedModel: {type(e).__name__}"
            )

    def _load_safetensors_model(self, model_path: str):
        """Load a safetensors model."""
        try:
            from safetensors import safe_open

            tensors = {}
            with safe_open(model_path, framework="pt") as f:
                for key in f.keys():
                    tensors[key] = f.get_tensor(key)
            return tensors
        except ImportError:
            raise ModelLoadError(
                "safetensors package is required for safetensors format"
            )
        except Exception as e:
            raise ModelLoadError(
                f"Failed to load safetensors model: {type(e).__name__}"
            )

    def load_latest_model(self):
        """
        Fetch and load the latest approved model version.

        Security measures:
        1. Only loads models from the approved registry (allowlist)
        2. Verifies SHA-256 checksum after download
        3. Only supports safe serialization formats (no pickle)
        4. Validates all inputs and paths
        """
        # Get latest approved version from registry
        version = self._registry.get_latest_approved_version(self._model_name)
        if version is None:
            raise ModelLoadError(
                f"No approved versions found for model '{self._model_name}' "
                f"in the model registry. Models must be pre-approved before "
                f"deployment."
            )

        logger.info(
            "Loading model '%s' version '%s'", self._model_name, version
        )

        return self.load_model_version(version)

    def load_model_version(self, version: str):
        """Load a specific approved model version with full integrity checks."""
        version = self._validate_version(version)

        # Step 1: Verify model is in the approved allowlist
        if not self._registry.is_model_approved(self._model_name, version):
            raise ModelLoadError(
                f"Model '{self._model_name}' version '{version}' is NOT in "
                f"the approved model registry. Refusing to load unapproved model."
            )

        # Step 2: Get expected checksum from registry
        expected_checksum = self._registry.get_approved_checksum(
            self._model_name, version
        )
        if not expected_checksum:
            raise ModelIntegrityError(
                f"No checksum found in registry for model '{self._model_name}' "
                f"version '{version}'. Cannot verify integrity."
            )

        # Step 3: Verify the model format is safe (no pickle-based formats)
        model_format = self._registry.get_approved_format(
            self._model_name, version
        )
        if model_format not in self.SAFE_FORMATS:
            raise ModelLoadError(
                f"Model format '{model_format}' is not in the safe formats "
                f"allowlist: {self.SAFE_FORMATS}. Pickle-based formats "
                f"(joblib, pkl, etc.) are prohibited due to arbitrary code "
                f"execution risks."
            )

        # Step 4: Construct the S3 key (validated components only)
        s3_key = f"{self._model_path_prefix}/{self._model_name}/{version}/model.{model_format}"

        # Step 5: Download to secure temp location
        safe_filename = f"model_{self._model_name}_{version}.{model_format}"
        safe_filename = re.sub(r'[^a-zA-Z0-9._\-]', '_', safe_filename)
        local_path = os.path.join(self._temp_dir, safe_filename)

        logger.info("Downloading model artifact...")
        self._download_model_artifact(s3_key, local_path)

        # Step 6: Verify cryptographic integrity
        logger.info("Verifying model integrity (SHA-256)...")
        if not self._verify_integrity(local_path, expected_checksum):
            # Delete the compromised file immediately
            os.unlink(local_path)
            raise ModelIntegrityError(
                f"INTEGRITY CHECK FAILED for model '{self._model_name}' "
                f"version '{version}'. The downloaded artifact does not match "
                f"the approved checksum. This may indicate model poisoning "
                f"or tampering. The artifact has been deleted."
            )

        logger.info("Integrity verification passed.")

        # Step 7: Load model using format-appropriate safe loader
        logger.info("Loading model in '%s' format...", model_format)
        try:
            if model_format == 'onnx':
                self._model = self._load_onnx_model(local_path)
            elif model_format == 'savedmodel':
                self._model = self._load_savedmodel(local_path)
            elif model_format == 'safetensors':
                self._model = self._load_safetensors_model(local_path)
            else:
                # This shouldn't happen due to allowlist check above
                raise ModelLoadError(f"Unsupported format: {model_format}")
        finally:
            # Clean up downloaded file after loading
            if os.path.exists(local_path):
                os.unlink(local_path)

        self._model_metadata = {
            'name': self._model_name,
            'version': version,
            'format': model_format,
            'loaded_at': datetime.utcnow().isoformat(),
            'checksum_verified': True,
        }

        logger.info(
            "Model '%s' version '%s' loaded successfully with verified integrity.",
            self._model_name, version
        )

        return self._model

    @property
    def model(self):
        """Get the currently loaded model."""
        if self._model is None:
            raise RuntimeError("No model loaded. Call load_latest_model() first.")
        return self._model

    @property
    def metadata(self) -> Dict[str, Any]:
        """Get metadata about the currently loaded model."""
        return self._model_metadata.copy()

    def cleanup(self):
        """Clean up temporary files."""
        if self._temp_dir and os.path.exists(self._temp_dir):
            import shutil
            shutil.rmtree(self._temp_dir, ignore_errors=True)
            logger.info("Cleaned up temporary directory")


