def main():
    """
    Production inference service startup.

    Required environment variables:
    - MODEL_BUCKET: S3 bucket name
    - MODEL_PATH_PREFIX: Path prefix within the bucket
    - MODEL_NAME: Name of the model to load
    - MODEL_REGISTRY_PATH: Path to the model registry JSON file

    Optional:
    - ALLOWED_BUCKETS: Comma-separated list of allowed bucket names
    """
    logger.info("Starting secure model loading service...")

    # Verify required environment variables are set
    required_vars = ['MODEL_BUCKET', 'MODEL_PATH_PREFIX', 'MODEL_NAME']
    missing = [v for v in required_vars if not os.environ.get(v)]
    if missing:
        logger.error(
            "Missing required environment variables: %s",
            ', '.join(missing)
        )
        logger.info(
            "Set the following environment variables:\n"
            "  MODEL_BUCKET=my-ml-models-bucket\n"
            "  MODEL_PATH_PREFIX=production/models\n"
            "  MODEL_NAME=text-classifier\n"
            "  MODEL_REGISTRY_PATH=/etc/ml-service/model_registry.json\n"
            "  ALLOWED_BUCKETS=my-ml-models-bucket (optional)"
        )
        sys.exit(1)

    loader = None
    try:
        loader = SecureModelLoader()
        model = loader.load_latest_model()

        logger.info("Model metadata: %s", json.dumps(loader.metadata, indent=2))
        logger.info("Model loaded and ready for inference.")

        # The model is now available via loader.model for inference
        # In a real service, you would pass this to your inference handler
        return loader

    except ModelIntegrityError as e:
        logger.critical("MODEL INTEGRITY FAILURE: %s", str(e))
        sys.exit(2)
    except ModelLoadError as e:
        logger.error("Model loading failed: %s", str(e))
        sys.exit(1)
    except ValueError as e:
        logger.error("Configuration error: %s", str(e))
        sys.exit(1)
    except Exception as e:
        logger.error("Unexpected error: %s", type(e).__name__)
        sys.exit(1)


if __name__ == '__main__':
    main()